SELECT bridge_auto_check_task(
  {{ $('Processar Classificação').item.json.mentorado_id }}::bigint,
  '{{ ($json.choices ? JSON.parse($json.choices[0].message.content).acao_concluida : ($json.acao_concluida || '')).replace(/'/g, "''") }}'::text,
  {{ ($json.choices ? JSON.parse($json.choices[0].message.content).evidencia : ($json.evidencia || null)) ? "'" + ($json.choices ? JSON.parse($json.choices[0].message.content).evidencia : $json.evidencia).replace(/'/g, "''") + "'" : 'NULL' }}::text,
  {{ $('Salvar Interação').item.json.id ? $('Salvar Interação').item.json.id : 'NULL' }}::bigint
);
